        // Clean up test files
        if (fs.existsSync(testDir)) {
            fs.rmSync(testDir, { recursive: true, force: true });
        }
    });

    it('should create ZipAFolder instance', function() {
        let zipper = new zip_a_folder.ZipAFolder();
        assert(zipper instanceof zip_a_folder.ZipAFolder);
