            // Verify zip file was created
            assert(fs.existsSync(zipPath));
            assert(fs.statSync(zipPath).size > 0);
            done();
        }).catch(done);
    });

    it('should handle empty folder', function(done) {
        let zipper = new zip_a_folder.ZipAFolder();
        let emptyDir = path.join(testDir, 'empty');
