        zipper.zip(emptyDir, zipPath).then(() => {
            assert(fs.existsSync(zipPath));
            done();
        }).catch(done);
    });

    it('should reject when source folder does not exist', function(done) {
        let zipper = new zip_a_folder.ZipAFolder();
        let nonExistentDir = path.join(testDir, 'nonexistent');

        zipper.zip(nonExistentDir, zipPath).then(() => {
            done(new Error('Should have rejected'));
        }).catch((err) => {
            assert(err instanceof Error);
            done();
        });
    });

    it('should reject when zip path is invalid', function(done) {
        let zipper = new zip_a_folder.ZipAFolder();
        let sourceDir = path.join(testDir, 'source');
        let invalidZipPath = path.join('/invalid/path/test.zip');

        zipper.zip(sourceDir, invalidZipPath).then(() => {
            done(new Error('Should have rejected'));
        }).catch((err) => {
            assert(err instanceof Error);
            done();
        });
    });
});
