let zip_a_folder = require('zip-a-folder');
let fs = require('fs');
let path = require('path');
let os = require('os');

describe('test zip_a_folder', function() {
    let testDir;
    let srcFolder;
    let targetFolder;

    beforeEach(async function() {
        // Create temporary directories for testing
        testDir = fs.mkdtempSync(path.join(os.tmpdir(), 'zip-test-'));
        srcFolder = path.join(testDir, 'source');
        targetFolder = path.join(testDir, 'target');

        fs.mkdirSync(srcFolder);
        fs.mkdirSync(targetFolder);

        // Create test files in source folder
        fs.writeFileSync(path.join(srcFolder, 'test1.txt'), 'Hello World');
        fs.writeFileSync(path.join(srcFolder, 'test2.txt'), 'Test content');

        // Create a subdirectory with a file
        const subDir = path.join(srcFolder, 'subdir');
        fs.mkdirSync(subDir);
        fs.writeFileSync(path.join(subDir, 'nested.txt'), 'Nested file content');
    });

    afterEach(function() {
        // Clean up test directories
        if (fs.existsSync(testDir)) {
            fs.rmSync(testDir, { recursive: true, force: true });
        }
    });

    it('should create a zip file with compression', async function() {
        const zipPath = path.join(targetFolder, 'test.zip');

        await zip_a_folder.ZipAFolder.zip(srcFolder, zipPath);

        assert(fs.existsSync(zipPath), 'Zip file should be created');
        assert(fs.statSync(zipPath).size > 0, 'Zip file should not be empty');
    });

    it('should create a zip file without compression', async function() {
        const zipPath = path.join(targetFolder, 'test-uncompressed.zip');
        const options = { compression: zip_a_folder.COMPRESSION_LEVEL.uncompressed };

        await zip_a_folder.ZipAFolder.zip(srcFolder, zipPath, options);

        assert(fs.existsSync(zipPath), 'Uncompressed zip file should be created');
        assert(fs.statSync(zipPath).size > 0, 'Uncompressed zip file should not be empty');
    });

    it('should create a tar file with compression', async function() {
        const tarPath = path.join(targetFolder, 'test.tar.gz');

        await zip_a_folder.ZipAFolder.tar(srcFolder, tarPath);

        assert(fs.existsSync(tarPath), 'Tar file should be created');
        assert(fs.statSync(tarPath).size > 0, 'Tar file should not be empty');
    });

    it('should create a tar file without compression', async function() {
        const tarPath = path.join(targetFolder, 'test-uncompressed.tar');
        const options = { compression: zip_a_folder.COMPRESSION_LEVEL.uncompressed };

        await zip_a_folder.ZipAFolder.tar(srcFolder, tarPath, options);

        assert(fs.existsSync(tarPath), 'Uncompressed tar file should be created');
        assert(fs.statSync(tarPath).size > 0, 'Uncompressed tar file should not be empty');
    });

    it('should throw error when source and target are the same', async function() {
        const zipPath = path.join(srcFolder, 'test.zip');

        try {
            await zip_a_folder.ZipAFolder.zip(srcFolder, zipPath);
            assert.fail('Should have thrown an error');
        } catch (error) {
            assert(error.message.includes('Source and target folder must be different'), 
                   'Should throw error about same source and target folder');
        }
    });

    it('should work with custom write stream', async function() {
        const zipPath = path.join(targetFolder, 'custom-stream.zip');
        const writeStream = fs.createWriteStream(zipPath);
        const options = { customWriteStream: writeStream };

        await zip_a_folder.ZipAFolder.compress({
            srcFolder: srcFolder,
            targetFilePath: null,
            format: 'zip',
            zipAFolderOptions: options
        });

        assert(fs.existsSync(zipPath), 'Zip file should be created with custom stream');
        assert(fs.statSync(zipPath).size > 0, 'Zip file should not be empty');
    });

    it('should throw error when no target path or custom stream provided', async function() {
        try {
            await zip_a_folder.ZipAFolder.compress({
                srcFolder: srcFolder,
                targetFilePath: null,
                format: 'zip',
                zipAFolderOptions: {}
            });
            assert.fail('Should have thrown an error');
        } catch (error) {
            assert(error.message.includes('You must either provide a target file path or a custom write stream'), 
                   'Should throw error about missing target or stream');
        }
    });
});
